'use strict';

// Mocha root hook plugin: force v8 coverage flush before mocha tears
// the worker down via IPC disconnect.  Partial mitigation for the
// parallel-mode race in V8 coverage collection — `build/test.sh` and
// `lsp/server/package.json` additionally disable `--parallel` under
// `CIVET_COVERAGE=1`, since `takeCoverage()` here cannot save hits
// generated by code that runs after `afterAll` (mocha's own teardown,
// reporters) before the IPC kill.
exports.mochaHooks = {
  afterAll() {
    if (process.env.NODE_V8_COVERAGE) {
      require('v8').takeCoverage();
    }
  },
};
